// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX 10000
// Define the structure for a tree node
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;
// Function to create a new tree node
Node* newNode(int data) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->data = data;
    node->left = node->right = NULL;
    return node;
}
// Function to find the bottom view of a binary tree
void bottomView(Node* root) {
    if (root == NULL) return;
    // Create a queue for level order traversal
    Node** queue = (Node**) malloc(sizeof(Node*) * MAX);
    int front = 0, rear = 0;
    queue[rear++] = root;
    // Create a map to store the last node at each horizontal distance
    int* map = (int*) malloc(sizeof(int) * (2 * MAX + 1));
    for (int i = 0; i < 2 * MAX + 1; i++) {
        map[i] = -1;
    }
    int hd = 0;
    while (front < rear) {
        Node* temp = queue[front++];
        // Update the map with the current node
        if (map[hd + MAX] == -1) {
            map[hd + MAX] = temp->data;
        }
        // Enqueue the left and right children
        if (temp->left) {
            queue[rear++] = temp->left;
            hd--;
        }
        if (temp->right) {
            queue[rear++] = temp->right;
            hd++;
        }
    }
    // Print the bottom view
    for (int i = 0; i < 2 * MAX + 1; i++) {
        if (map[i] != -1) printf("%d ", map[i]);
    }
    printf("\n");
    free(queue);
    free(map);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node* root = NULL;
        int* arr = (int*) malloc(sizeof(int) * N);
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        // Create the binary tree
        root = newNode(arr[0]);
        Node** queue = (Node**) malloc(sizeof(Node*) * MAX);
        int front = 0, rear = 0;
        queue[rear++] = root;
        int i = 1;
        while (front < rear && i < N) {
            Node* temp = queue[front++];
            if (arr[i] != -1) {
                temp->left = newNode(arr[i]);
                queue[rear++] = temp->left;
            }
            i++;
            if (i < N && arr[i] != -1) {
                temp->right = newNode(arr[i]);
                queue[rear++] = temp->right;
            }
            i++;
        }
        free(queue);
        // Find and print the bottom view
        bottomView(root);
        free(arr);
    }
    return 0;
}

