#include <iostream>
#include <queue>
#include <unordered_map>
using namespace std;
// Define the structure for a tree node
struct Node {
    int data;
    Node* left;
    Node* right;
};
// Function to create a new tree node
Node* newNode(int data) {
    Node* node = new Node();
    node->data = data;
    node->left = node->right = NULL;
    return node;
}
// Function to find the bottom view of a binary tree
void bottomView(Node* root) {
    if (root == NULL) return;
    // Create a queue for level order traversal
    queue<Node*> q;
    q.push(root);
    // Create a map to store the last node at each horizontal distance
    unordered_map<int, int> map;
    int hd = 0;
    while (!q.empty()) {
        Node* temp = q.front();
        q.pop();
        // Update the map with the current node
        if (map.find(hd) == map.end()) {
            map[hd] = temp->data;
        }
        // Enqueue the left and right children
        if (temp->left) {
            q.push(temp->left);
            hd--;
        }
        if (temp->right) {
            q.push(temp->right);
            hd++;
        }
    }
    // Print the bottom view
    for (auto& it : map) {
        cout << it.second << " ";
    }
    cout << endl;
}
int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Node* root = NULL;
        int* arr = new int[N];
        for (int i = 0; i < N; i++) {
            cin >> arr[i];
        }
        // Create the binary tree
        root = newNode(arr[0]);
        queue<Node*> q;
        q.push(root);
        int i = 1;
        while (!q.empty() && i < N) {
            Node* temp = q.front();
            q.pop();
            if (arr[i] != -1) {
                temp->left = newNode(arr[i]);
                q.push(temp->left);
            }
            i++;
            if (i < N && arr[i] != -1) {
                temp->right = newNode(arr[i]);
                q.push(temp->right);
            }
            i++;
        }
        // Find and print the bottom view
        bottomView(root);
        delete[] arr;
    }
    return 0;
}

