// COMPLETE, COMPILABLE Java code
import java.util.Queue;
import java.util.LinkedList;
import java.util.HashMap;
public class Main {
    // Define the structure for a tree node
    static class Node {
        int data;
        Node left;
        Node right;
        Node(int data) {
            this.data = data;
            this.left = null;
            this.right = null;
        }
    }
    // Function to create a new tree node
    static Node newNode(int data) {
        return new Node(data);
    }
    // Function to find the bottom view of a binary tree
    static void bottomView(Node root) {
        if (root == null) return;
        // Create a queue for level order traversal
        Queue<Node> q = new LinkedList<>();
        q.add(root);
        // Create a map to store the last node at each horizontal distance
        HashMap<Integer, Integer> map = new HashMap<>();
        int hd = 0;
        while (!q.isEmpty()) {
            Node temp = q.poll();
            // Update the map with the current node
            if (!map.containsKey(hd)) {
                map.put(hd, temp.data);
            }
            // Enqueue the left and right children
            if (temp.left != null) {
                q.add(temp.left);
                hd--;
            }
            if (temp.right != null) {
                q.add(temp.right);
                hd++;
            }
        }
        // Print the bottom view
        for (int key : map.keySet()) {
            System.out.print(map.get(key) + " ");
        }
        System.out.println();
    }
    public static void main(String[] args) {
        int T;
        Scanner sc = new Scanner(System.in);
        T = sc.nextInt();
        while (T-- > 0) {
            int N;
            N = sc.nextInt();
            Node root = null;
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            // Create the binary tree
            root = newNode(arr[0]);
            Queue<Node> q = new LinkedList<>();
            q.add(root);
            int i = 1;
            while (!q.isEmpty() && i < N) {
                Node temp = q.poll();
                if (arr[i] != -1) {
                    temp.left = newNode(arr[i]);
                    q.add(temp.left);
                }
                i++;
                if (i < N && arr[i] != -1) {
                    temp.right = newNode(arr[i]);
                    q.add(temp.right);
                }
                i++;
            }
            // Find and print the bottom view
            bottomView(root);
        }
    }
}

